def merge_within(pairs):
    sorted_pairs = sorted(pairs)
    merged = []
    start, current_end = sorted_pairs[0][0], sorted_pairs[0][1]

    for pair in sorted_pairs:
        if pair[0] <= current_end:
            current_end = max(pair[1], current_end)
        else:
            merged.append([start, current_end])
            start, current_end = pair[0], pair[1]

    if start < current_end:
        merged.append([start, current_end])

    return merged
